/**
 * Mutation-hardening tests for the base64 alphabet guard in images.ts.
 *
 * Targets the `^` start-anchor in BASE64_PATTERN. Without the anchor, a hostile caller could
 * prepend arbitrary junk (whitespace, control bytes, injection payloads) and still match,
 * because the regex would only require the *suffix* to be valid base64. These boundary-exact
 * tests fail closed on a leading-junk payload, killing the anchor-removal mutant.
 */
import { describe, expect, it } from 'vitest';
import { safeParseImageRef } from './images.js';

describe('images base64 guard — start anchor (mutation-hardening)', () => {
  it('rejects a payload with a junk prefix followed by valid base64 (anchored ^)', () => {
    // 'AAAA' alone is valid base64; the leading junk must make the WHOLE string fail.
    // An un-anchored regex would match the trailing 'AAAA' and wrongly accept this.
    const result = safeParseImageRef({
      kind: 'base64',
      mimeType: 'image/png',
      data: '!!not-base64##AAAA',
    });
    expect(result.success).toBe(false);
  });

  it('rejects leading-whitespace + valid base64 (anchor must pin the start)', () => {
    const result = safeParseImageRef({
      kind: 'base64',
      mimeType: 'image/png',
      data: '   aGVsbG8=',
    });
    expect(result.success).toBe(false);
  });

  it('still accepts a clean base64 payload (no false positive from the anchor)', () => {
    expect(
      safeParseImageRef({ kind: 'base64', mimeType: 'image/png', data: 'aGVsbG8=' }).success,
    ).toBe(true);
  });
});

src/tryon-result-url-anchor.mutation.tes.source:
/**
 * Mutation-hardening tests for the result-image data-URL guard in tryon.ts.
 *
 * Targets the `^` start-anchor in RESULT_IMAGE_DATA_URL_PATTERN. Without the anchor, a hostile
 * provider could prefix a dangerous scheme (e.g. `javascript:`) and still match because the
 * regex would only require the *tail* to look like a safe data-url. These tests assert the
 * whole string must start with the safe `data:image/...` shape, killing the anchor-removal mutant.
 */
import { describe, expect, it } from 'vitest';
import { isAcceptableResultImageUrl } from './tryon.js';

describe('isAcceptableResultImageUrl — start anchor (mutation-hardening)', () => {
  it('rejects a javascript-scheme prefix in front of a valid data-url tail (anchored ^)', () => {
    // The trailing `data:image/png;base64,AAAA` is well-formed; the leading scheme must
    // make the whole string fail. An un-anchored regex would wrongly accept this.
    expect(
      isAcceptableResultImageUrl('javascript:alert(1)//data:image/png;base64,AAAA'),
    ).toBe(false);
  });

  it('rejects arbitrary leading text before a valid data-url tail', () => {
    expect(isAcceptableResultImageUrl('XXXdata:image/png;base64,AAAA')).toBe(false);
  });

  it('still accepts a clean data:image url (no false positive from the anchor)', () => {
    expect(isAcceptableResultImageUrl('data:image/png;base64,aGVsbG8=')).toBe(true);
  });
});
